          'description' => 'Product URL to monitor (e.g. \'https://www.amazon.com/dp/...\' or any product page).',
        ),
        'selector' => 
        array (
          'type' => 'string',
          'description' => 'Price selector: CSS selector (e.g. \'.price\', \'#priceblock_ourprice\', \'.a-price-whole\') or XPath (e.g. \'//span[@class="price"]\'). Default: auto-detect using common price patterns.',
        ),
        'name' => 
